            self._print(Style.CYAN(f"System${self.id}:"), end=" ", flush=flush)
        if isinstance(text, str) and kwargs == {} and text:
            stram_print(text + ' '.join(args))
            self._print()
        else:
            self._print(text, *args, **kwargs, flush=flush)

